import { Box, CardMedia, Container, Grid } from "@mui/material";
import Barra from "../../Commons/Barra";
import { CopyRight } from "../../Commons/Copyright";

export default function ButtonAppBar() {
  return (
    <>
      <Barra/>
      <Container sx={{py:36, border:1}} maxWidth="xl">
        <Grid container spacing={4}> 
          <Grid item
            sx={{border:1, backgroundImage:"https://www.businessempresarial.com.pe/wp-content/uploads/2023/03/departamentos-de-lujo-2.jpeg",
            backgroundRepeat:"no-repeat"}}>
            
          </Grid>
          <Grid item sx={{border:1, width:300}}>
            <Box sx={{bgcolor:"#cfe8fc", height:"50vh"}}/>
          </Grid>

        </Grid>
      </Container>
      <CopyRight/>
    </>
  );
}
